#root {    
  margin: 0px;
  padding: 0px;
  overflow: hidden;
  background-color: #58A399;
  color: #496989;
}

.same-row-children {
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: center;
}

section {
  margin-top: 20px
}

footer {
  margin-top: 40px;
}

fieldset {
  margin-top: 30px;
}


form input {
  display: block;
  border: 1px solid #496989;
  border-radius: 5px;
}

input[type="text"] {
  background-color: #496989;
  color: #58A399;
  border: 2px solid #58A399; 
  border-radius: 5px; /* Slight rounding of corners */
  padding: 5px; /* Adds some padding inside the input */
}

input[type="email"] {
  background-color: #58A399;
  color: #496989;
  border: 2px dashed #496989; /* Dashed border for distinction */
  border-radius: 10px; /* Keeps the original border-radius */
  padding: 8px; /* Slightly more padding */
}

input[type="password"] {
  background-color: #58A399;
  color: #496989;
  border: 3px double #496989; /* Double border for a unique look */
  border-radius: 0; /* No border-radius */
  padding: 5px;
  box-shadow: 0px 2px 4px #496989; /* Adds a shadow for depth */
}

input[type="number"] {
  background-color: #496989;
  color: #58A399;
  border: none; /* No border */
  border-radius: 15px; /* Increased border-radius */
  padding: 5px;
  box-shadow: 0px -2px 4px #58A399; /* Shadow for a lifted effect */
}

input[type="checkbox"] {
  appearance: none;
  background-color: #496989;
  margin: 0;
  font: inherit;
  color: currentColor;
  width: 1.15em;
  height: 1.15em;
  border: 0.15em solid currentColor;
  border-radius: 0.15em;
  transform: translateY(-0.075em);
  display: grid;
  place-content: center;
}

input[type="checkbox"]::before {
  content: "";
  width: 0.65em;
  height: 0.65em;
  transform: scale(0);
  transition: 120ms transform ease-in-out;
  box-shadow: inset 1em 1em #58A399;
  /* Windows High Contrast Mode */
  background-color: CanvasText;
  transform-origin: bottom left;
  clip-path: polygon(14% 44%, 0 65%, 50% 100%, 100% 16%, 80% 0%, 43% 62%);
}

input[type="checkbox"]:checked::before {
  transform: scale(1);
}


